INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('1ced6e0c7b0ff1254d0d9783dc1e31d8bd9a8d493809e5704c2a8baf598c9a11', 'https://andykondo.substack.com/p/ev100-3ab', '明治時代のEVがスゴすぎた【前編】水車小屋で充電するから再エネ100％【ドイツ現地レポート】', 'ドイツでとあるEVメーカーの最新モデルを試乗レポートしてきました。メーカーの名前は「フロッケン」。ドイツ・バイエルン州コーブルク発の、新進気鋭のEVメーカーです。……1888年製です。創業者アンドレアス・フロッケンは農業機械メーカーから独立', 'https://d3t3ozftmdmh3i.cloudfront.net/staging/podcast_uploaded_nologo/43876985/43876985-1775564176368-1b699d25fffec.jpg', '2026-04-10T00:49:39+00:00', 'Andy Kondo - Innovation Analyst', 'ビジネス') ON CONFLICT(url) DO NOTHING;
